var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"교관님! 낙오됐던 친구들은 전부 구조했습니다!","JPN":"教官！　はぐれたメンバーは全員救助しました！","ENG":"Sir! We've secured all the stragglers!","TWN":"教官！脫隊人都救回來了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"잘했다, 폭탄은?","JPN":"よくやった、爆弾は？","ENG":"Good. How are we doing with firepower?","TWN":"非常好，那炸彈呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"바, 방금 전에 던진 수류탄이 마지막이었습니다! 이제 더는 없어요!","JPN":"さ、さっき投げた手榴弾が最後でした！　もうありません！","ENG":"W-we just tossed our last grenade! We're all out of explosives!","TWN":"剛剛扔出去的手榴彈是最後一顆，都沒有了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"어쩌죠? 저것들 우리를 붙잡으면 갈기갈기 찢을 기세던데……!","JPN":"どうしましょう？　切り裂くような勢いで追撃してきます……！","ENG":"What should we do? They're going to tear us to pieces if they catch up to us…","TWN":"怎麼辦？感覺那些人抓到我們後，會把我們生吞活剝……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……기다려. 지금 생각 중이다.","JPN":"……待ってくれ。今考え中だ。","ENG":"…Give me a minute. I'm trying to think.","TWN":"……先不要急，我正在想辦法。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"어리석은 것들. 우리 형제들에게서 벗어날 수 있을 줄 알았느냐?","JPN":"愚か者め。我が兄弟の手から逃れられると思ったのか？","ENG":"Fools. Did you really think you could escape us?","TWN":"愚蠢的傢伙，以為可以逃出我們弟兄的五指山嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"포기해라. 계속 저항한다면 차라리 죽여 달라고 빌게 해 주지.","JPN":"諦めろ。抵抗し続けるならいっそ殺してくれと懇願するまで痛めつけてやる。","ENG":"Yield. If you continue to resist, we'll make you wish you were dead.","TWN":"放棄吧！再繼續抵抗的話，我會讓你們生不如死！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……주교 엘카노. 본명 로버트 리.","JPN":"……司教エルカノ。本名ロバート・リー。","ENG":"…Bishop Elcano. Real name, Robert Lee.","TWN":"……主教 埃爾卡諾，本名 羅伯特·李。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"음? 내 이름을 어떻게……?","JPN":"うむ？　私の名前をどうして……？","ENG":"Huh? How did you know my name?","TWN":"嗯？你怎麼知道我的名字…？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"다단계 사기를 저지르고 국외 도피했다가 예언회에 투신했던 쓰레기, 맞나?","JPN":"ネズミ講詐欺を犯して国外逃亡し、預言会に潜んだクズ、で合ってるか？","ENG":"A scumbag who fled overseas after a failed pyramid scheme, only to take refuge with the MPS. That sound about right?","TWN":"犯下多個詐騙案逃往海外後，加入預言會的垃圾，我沒說錯吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"이, 이 거지 주제에 내 뒷조사를 했다고?!","JPN":"お、お前、乞食のくせに私のことを探ったな！？","ENG":"Y-you dared dig up my history, you vagrant?!","TWN":"你…竟敢私下調查我？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"그래, 그래서 그게 어쨌다는 거지!","JPN":"ああ、それがどうした？","ENG":"So what?","TWN":"沒錯，你說的沒錯又怎樣？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너한테 속은 사람들이 얼마나 고통스럽게 하루하루를 보냈을지, 잠시라도 생각해 본 적 있나?","JPN":"貴様に騙されてどれほど多くの人々がどれだけ苦しんだのか、考えたことはあるのか？","ENG":"Have you ever thought about how many innocent people suffered because of your scheme?","TWN":"你有一時片刻想過，那些被你騙的人每天過得有多痛苦嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"……하. 무슨 소리를 하나 했더니.","JPN":"……はっ。　何を言い出すかと思ったら。","ENG":"Ha… So that's what you wanted to talk about?","TWN":"……哈，我還以為你要說什麼。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"그들이 바친 돈은 예언을 이루는 데 쓰였다! 이만큼 값진 투자가 어디 있단 말이냐!","JPN":"奴らが貢いだ金は預言を成し遂げるのに使われた！　こんな貴重な投資は他にないだろうが！","ENG":"Their offerings were well spent on making the prophecy come true! What better investment is there?","TWN":"他們奉獻的錢是用來實現預言的！有比這更划算的投資嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"겁에 질려서 얼굴도 못 내미는 놈이 건방지게! 네놈은 특별히 내 손으로 처단해 주마!","JPN":"怖がって顔も出せない奴が生意気に！　お前は特別に私の手で断罪してやろう！","ENG":"You dare judge me? You're nothing but a coward who won't even show your face! I'll make a special exception, and take you out myself!","TWN":"因為害怕而不敢露臉的傢伙，還敢給我說什麼大道理！我就特別親手處決你吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네가 예언회에서 한 자리 차지하는 데 썼겠지. 그것도 투자라면 투자겠군.","JPN":"あんたが預言会でのし上がるために使ったんだろう。それも投資というなら投資だろうな。","ENG":"I bet you used that money to bribe your way to the top within the MPS. Then again, I guess you really could call that an investment of sorts.","TWN":"那些錢應該也有用來幫助你，在預言會取得一席之地吧？那也算投資吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};